export default {
	data() {
		return {
			key: '',
			btns: [{ title: '我负责的', value: '1' }, { title: '共享给我的', value: '2' }, { title: '我管理的', value: '3' }], //客户归属
			mode: false,
			activeBtn: 0, //默认选择第一个
			searcData: {
				type: '1',
				pid: ''
			}
		};
	},
	props: {
		showCustomer: {
			type: Boolean,
			default: false
		},
		isSingle: {
			//是否是单选
			type: Boolean,
			default: false
		}
	},
	mounted() {
		//当组件为单选时
		if(this.isSingle == true){
			if (this.pro) {
				this.pro.forEach(res => {
					res.project.forEach(resp => {
						resp.isactive = false
					});
				});
			}
		}
	},
	computed: {
		pro() {
			return this.$store.state.searchPro;
		},
		//判断所有楼盘是否全选
		allChoose() {
			var choose = false;
			var dataTrue = [];
			var num = 0;
			if (this.pro) {
				this.pro.forEach(res => {
					num = num + res.project.length;
					res.project.forEach(resp => {
						if (resp.isactive == false) {
							choose = false;
						} else {
							dataTrue.push(resp);
						}
					});
				});
				if (num != dataTrue.length) {
					choose = true;
				}
			}

			return choose;
		}
	},
	methods: {
		allChooseList(list) {
			var choose = false;
			var c = [];
			if (list) {
				list.forEach(res => {
					if (res.isactive == false) {
						choose = true;
					} else {
						c.push(res);
					}
				});
				if (c.length == list.length) {
					choose = false;
				}
			}
			return choose;
		},
		chooseBtn(item, index) {
			this.activeBtn = index;
			this.searcData.type = item.value;
		},
		//所有楼盘全选
		allSelected(index) {
			if (index == 0) {
				this.pro.forEach(res => {
					res.project.forEach(resp => {
						resp.isactive = false;
					});
				});
			}
			if (index == 1) {
				this.pro.forEach(res => {
					res.project.forEach(resp => {
						resp.isactive = true;
					});
				});
			}
			this.$forceUpdate();
		},
		selected(items) {
			//当类型为单选时
			if(this.isSingle == true){
				if (this.pro) {
					this.pro.forEach(res => {
						res.project.forEach(resp => {
							resp.isactive = false
						});
					});
				}
				items.isactive = true;
			}else{
				items.isactive = !items.isactive;
			}
			this.$forceUpdate();
		},
		//区域全选
		all(list, index) {
			//0 是取消全选 1 全选
			if (index == 0) {
				list.forEach(res => {
					res.isactive = false;
				});
			}
			if (index == 1) {
				list.forEach(res => {
					res.isactive = true;
				});
			}
			this.$forceUpdate();
		},

		moveHandle() {},
		cancel() {
			this.mode = false;
		},
		show() {
			this.mode = true;
		},
		sub() {
			this.mode = false;
			let pids = [];
			let p_name =''
			this.pro.forEach(res => {
				res.project.forEach(resp => {
					if (resp.isactive == true) {
						pids.push(resp.p_id);
						p_name = resp.p_name;
					}
				});
			});
			this.searcData.pid = pids;
			if(this.isSingle == true){
				let data ={
					pid:pids,
					p_name:p_name
				}
				this.$emit('confirm', data);
			}else{
				this.$emit('confirm', this.searcData);
			}
		}
	}
};
